"""Long stiffener geometry."""

from fhecor_structuralcodes.geometry._plate import Plate, assemble_inertia


class Long_stiffener:
    """Longitudinal stiffener formed by a list of plates."""

    plates: list[Plate]

    def __init__(self, plates: list[Plate]):
        self.plates = plates

    @property
    def area(self) -> float:
        """Property to access the area of the long stiffener."""
        return sum([chapa.area for chapa in self.plates])

    @property
    def Iyy(self) -> float:
        """Moment of inertia of the long stiffener around the y-axis."""
        return assemble_inertia(self.plates)[0]

    @property
    def Izz(self) -> float:
        """Moment of inertia of the long stiffener around the z-axis."""
        return assemble_inertia(self.plates)[1]

    @property
    def Iyz(self) -> float:
        """Moment of inertia of the long stiffener around the yz-axis."""
        return assemble_inertia(self.plates)[2]

    @property
    def properties(self) -> float:
        """mechanical properties of the long stiffener."""
        prop = []
        prop.append(f"Area: {self.area*1e-2:.1f} cm²")
        prop.append(f"Iyy: {self.Iyy*1e-4:.0f} cm⁴")
        prop.append(f"Izz: {self.Izz*1e-4:.0f} cm⁴")
        prop.append(f"Iyz: {self.Iyz*1e-4:.0f} cm⁴")
        text = "\n".join(prop)
        return text
